WITH target AS (
  SELECT c.id AS candidato_id
  FROM candidatos c
  WHERE c.slug = 'alexandre-curi' AND c.publicavel = true
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM target
CROSS JOIN _seed_alexandre_curi_alep_autoria_lote_a AS seed
ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
  tipo = EXCLUDED.tipo,
  numero = EXCLUDED.numero,
  ano = EXCLUDED.ano,
  ementa = EXCLUDED.ementa,
  fonte = EXCLUDED.fonte,
  url_inteiro_teor = EXCLUDED.url_inteiro_teor,
  coverage_id = EXCLUDED.coverage_id,
  coverage_scope = EXCLUDED.coverage_scope,
  metadata = COALESCE(projetos_lei.metadata, '{}'::jsonb) || EXCLUDED.metadata
WHERE projetos_lei.coverage_id IS NULL
   OR projetos_lei.coverage_id = EXCLUDED.coverage_id;

DO $$
DECLARE
  cand_id uuid;
  total_count int;
  target_count int;
  coverage_count int;
  wrong_lme_count int;
  rejected_present_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'alexandre-curi' AND publicavel = true;

  IF cand_id IS NULL THEN
    RAISE NOTICE 'alexandre-curi: pos-condicao pulada porque candidato publico nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('ALEP-AUTORIA:435:PL:417/2026:DAP-1818/2026', 'ALEP-AUTORIA:435:PL:411/2026:DAP-1789/2026', 'ALEP-AUTORIA:435:PL:348/2026:DAP-1528/2026', 'ALEP-AUTORIA:435:PL:339/2026:DAP-1487/2026', 'ALEP-AUTORIA:435:PL:338/2026:DAP-1486/2026', 'ALEP-AUTORIA:435:PL:254/2026:DAP-983/2026', 'ALEP-AUTORIA:435:PL:249/2026:DAP-968/2026', 'ALEP-AUTORIA:435:PL:203/2026:DAP-772/2026', 'ALEP-AUTORIA:435:PL:202/2026:DAP-771/2026', 'ALEP-AUTORIA:435:PL:162/2026:DAP-558/2026', 'ALEP-AUTORIA:435:PL:160/2026:DAP-554/2026', 'ALEP-AUTORIA:435:PL:149/2026:DAP-507/2026', 'ALEP-AUTORIA:435:PL:101/2026:DAP-341/2026', 'ALEP-AUTORIA:435:PL:82/2026:DAP-230/2026', 'ALEP-AUTORIA:435:PL:76/2026:DAP-171/2026', 'ALEP-AUTORIA:435:PL:71/2026:DAP-162/2026', 'ALEP-AUTORIA:435:PL:70/2026:DAP-160/2026', 'ALEP-AUTORIA:435:PL:69/2026:DAP-159/2026', 'ALEP-AUTORIA:435:PL:68/2026:DAP-158/2026', 'ALEP-AUTORIA:435:PL:67/2026:DAP-157/2026', 'ALEP-AUTORIA:435:PL:66/2026:DAP-156/2026', 'ALEP-AUTORIA:435:PL:65/2026:DAP-155/2026', 'ALEP-AUTORIA:435:PL:1250/2025:DAP-6237/2025', 'ALEP-AUTORIA:435:PL:1249/2025:DAP-6235/2025', 'ALEP-AUTORIA:435:PL:1223/2025:DAP-6095/2025', 'ALEP-AUTORIA:435:PL:1215/2025:DAP-6079/2025', 'ALEP-AUTORIA:435:PL:1207/2025:DAP-6050/2025', 'ALEP-AUTORIA:435:PL:1198/2025:DAP-5947/2025', 'ALEP-AUTORIA:435:PL:1194/2025:DAP-5931/2025', 'ALEP-AUTORIA:435:PL:1099/2025:DAP-5422/2025', 'ALEP-AUTORIA:435:PL:1091/2025:DAP-5377/2025', 'ALEP-AUTORIA:435:PL:1089/2025:DAP-5364/2025', 'ALEP-AUTORIA:435:PL:1088/2025:DAP-5362/2025', 'ALEP-AUTORIA:435:PL:1085/2025:DAP-5321/2025', 'ALEP-AUTORIA:435:PL:1054/2025:DAP-5146/2025', 'ALEP-AUTORIA:435:PL:1023/2025:DAP-4988/2025', 'ALEP-AUTORIA:435:PL:928/2025:DAP-4539/2025', 'ALEP-AUTORIA:435:PL:926/2025:DAP-4527/2025', 'ALEP-AUTORIA:435:PL:925/2025:DAP-4523/2025', 'ALEP-AUTORIA:435:PL:898/2025:DAP-4429/2025', 'ALEP-AUTORIA:435:PL:854/2025:DAP-4274/2025', 'ALEP-AUTORIA:435:PL:853/2025:DAP-4273/2025', 'ALEP-AUTORIA:435:PL:818/2025:DAP-4125/2025', 'ALE