    RAISE EXCEPTION 'Pos-apply alexandre-curi: % rejected rows foram inseridas indevidamente', rejected_present_count;
  END IF;

  RAISE NOTICE 'Pos-apply alexandre-curi ALEP Lote A: projetos_lei=% coverage_rows=%', total_count, coverage_count;
END $$;
